const input = $input.first().json;
const action = input.action || 'search_emails';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY,
  'Content-Type': 'application/json'
};

// === Google OAuth Token Helper ===
async function getGoogleToken() {
  const creds = await helpers.httpRequest({
    method: 'GET',
    url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&select=cred_key,cred_value',
    headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY }
  });
  const m = {};
  for (const c of creds) m[c.cred_key] = c.cred_value;

  if (!m.access_token || !m.refresh_token) {
    throw new Error('Google OAuth not configured. Install a Google skill and complete authorization first.');
  }

  if (new Date(m.token_expiry || 0) <= new Date(Date.now() + 5 * 60 * 1000)) {
    const resp = await helpers.httpRequest({
      method: 'POST',
      url: 'https://oauth2.googleapis.com/token',
      headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
      body: 'grant_type=refresh_token'
        + '&refresh_token=' + encodeURIComponent(m.refresh_token)
        + '&client_id=' + encodeURIComponent(m.client_id)
        + '&client_secret=' + encodeURIComponent(m.client_secret)
    });
    if (resp.error) throw new Error('Token refresh failed: ' + resp.error_description);

    const newExpiry = new Date(Date.now() + (resp.expires_in - 60) * 1000).toISOString();
    for (const [key, val] of [['access_token', resp.access_token], ['token_expiry', newExpiry]]) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.' + key, headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: key, cred_value: val }) });
    }
    if (resp.refresh_token) {
      await helpers.httpRequest({ method: 'DELETE', url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.google-oauth&cred_key=eq.refresh_token', headers: { ...pgHeaders, 'Prefer': 'return=minimal' } });
      await helpers.httpRequest({ method: 'POST', url: SUPABASE_URL + '/rest/v1/template_credentials', headers: { ...pgHeaders, 'Prefer': 'return=minimal' }, body: JSON.stringify({ template_id: 'google-oauth', cred_key: 'refresh_token', cred_value: resp.refresh_token }) });
    }
    return resp.access_token;
  }
  return m.access_token;
}

let accessToken;
try {
  accessToken = await getGoogleToken();
} catch(e) {
  return [{ json: { error: e.message } }];
}

const gHeaders = {
  'Authorization': 'Bearer ' + accessToken,
  'Content-Type': 'application/json'
};
const GMAIL_BASE = 'https://gmail.googleapis.com/gmail/v1/users/me';

// === search_emails ===
if (action === 'search_emails') {
  const query = input.query;
  if (!query) return [{ json: { error: 'Parameter "query" is required. Use Gmail search syntax (e.g. "from:user@example.com", "is:unread", "subject:hello").' } }];
  const maxResults = parseInt(input.max_results) || 10;

  try {
    const listResp = await helpers.httpRequest({
      method: 'GET',
      url: GMAIL_BASE + '/messages?q=' + encodeURIComponent(query) + '&maxResults=' + maxResults,
      headers: gHeaders
    });

    if (!listResp.messages || listResp.messages.length === 0) {
      return [{ json: { result: 'No emails found for query: ' + query } }];
    }

    let result = 'Found ' + (listResp.resultSizeEstimate || listResp.messages.length) + ' emails for "' + query + '":\n\n';

    for (const msg of listResp.messages.slice(0, maxResults)) {
      const detail = await helpers.httpRequest({
        method: 'GET',
        url: GMAIL_BASE + '/messages/' + msg.id + '?format=metadata&metadataHeaders=From&metadataHeaders=Subject&metadataHeaders=Date',
        headers: gHeaders
      });
      const headers = detail.payload && detail.payload.headers ? detail.payload.headers : [];
      const from = (headers.find(h => h.name === 'From') || {}).value || 'Unknown';
      const subject = (headers.find(h => h.name === 'Subject') || {}).value || '(no subject)';
      const date = (headers.find(h => h.name === 'Date') || {}).value || '';
      const labels = (detail.labelIds || []).join(', ');
      const snippet = detail.snippet || '';

      result += '**' + subject + '**\n';
      result += 'From: ' + from + '\n';
      result += 'Date: ' + date + '\n';
      result += 'ID: ' + msg.id + '\n';
      if (labels) result += 'Labels: ' + labels + '\n';
      if (snippet) result += snippet.substring(0, 150) + '\n';
      result += '\n';
    }
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Gmail search failed: ' + e.message } }];
  }

// === read_email ===
} else if (action === 'read_email') {
  const messageId = input.message_id;
  if (!messageId) return [{ json: { error: 'Parameter "message_id" is required.' } }];

  try {
    const msg = await helpers.httpRequest({
      method: 'GET',
      url: GMAIL_BASE + '/messages/' + messageId + '?format=full',
      headers: gHeaders
    });

    const headers = msg.payload && msg.payload.headers ? msg.payload.headers : [];
    const from = (headers.find(h => h.name === 'From') || {}).value || 'Unknown';
    const to = (headers.find(h => h.name === 'To') || {}).value || '';
    const subject = (headers.find(h => h.name === 'Subject') || {}).value || '(no subject)';
    const date = (headers.find(h => h.name === 'Date') || {}).value || '';

    // Extract body
    let body = '';
    function extractText(part) {
      if (part.mimeType === 'text/plain' && part.body && part.body.data) {
        body += Buffer.from(part.body.data, 'base64url').toString('utf-8');
      } else if (part.parts) {
        for (const p of part.parts) extractText(p);
      }
    }
    if (msg.payload) extractText(msg.payload);
    if (!body && msg.snippet) body = msg.snippet;

    let result = '**' + subject + '**\n';
    result += 'From: ' + from + '\n';
    result += 'To: ' + to + '\n';
    result += 'Date: ' + date + '\n';
    result += 'Labels: ' + (msg.labelIds || []).join(', ') + '\n\n';
    if (body.length > 5000) {
      result += body.substring(0, 5000) + '\n\n... (truncated, ' + body.length + ' chars total)';
    } else {
      result += body;
    }
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to read email: ' + e.message } }];
  }

// === send_email ===
} else if (action === 'send_email') {
  const to = input.to;
  const subject = input.subject;
  const body = input.body;
  if (!to || !subject || !body) return [{ json: { error: 'Parameters "to", "subject", and "body" are required.' } }];

  try {
    let rawEmail = 'To: ' + to + '\r\n';
    if (input.cc) rawEmail += 'Cc: ' + input.cc + '\r\n';
    if (input.bcc) rawEmail += 'Bcc: ' + input.bcc + '\r\n';
    rawEmail += 'Subject: ' + subject + '\r\n';
    rawEmail += 'Content-Type: text/plain; charset=UTF-8\r\n';
    rawEmail += '\r\n' + body;

    const encoded = Buffer.from(rawEmail).toString('base64url');

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: GMAIL_BASE + '/messages/send',
      headers: gHeaders,
      body: JSON.stringify({ raw: encoded })
    });

    return [{ json: { result: 'Email sent successfully to ' + to + '. Message ID: ' + resp.id } }];
  } catch(e) {
    return [{ json: { error: 'Failed to send email: ' + e.message } }];
  }

// === create_draft ===
} else if (action === 'create_draft') {
  const to = input.to;
  const subject = input.subject;
  const body = input.body;
  if (!to || !subject || !body) return [{ json: { error: 'Parameters "to", "subject", and "body" are required.' } }];

  try {
    let rawEmail = 'To: ' + to + '\r\n';
    rawEmail += 'Subject: ' + subject + '\r\n';
    rawEmail += 'Content-Type: text/plain; charset=UTF-8\r\n';
    rawEmail += '\r\n' + body;

    const encoded = Buffer.from(rawEmail).toString('base64url');

    const resp = await helpers.httpRequest({
      method: 'POST',
      url: GMAIL_BASE + '/drafts',
      headers: gHeaders,
      body: JSON.stringify({ message: { raw: encoded } })
    });

    return [{ json: { result: 'Draft created successfully. Draft ID: ' + resp.id } }];
  } catch(e) {
    return [{ json: { error: 'Failed to create draft: ' + e.message } }];
  }

// === list_labels ===
} else if (action === 'list_labels') {
  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: GMAIL_BASE + '/labels',
      headers: gHeaders
    });

    if (!resp.labels || resp.labels.length === 0) {
      return [{ json: { result: 'No labels found.' } }];
    }

    let result = 'Gmail Labels:\n\n';
    const system = resp.labels.filter(l => l.type === 'system');
    const user = resp.labels.filter(l => l.type === 'user');

    if (user.length > 0) {
      result += 'User Labels:\n';
      for (const l of user) result += '- ' + l.name + ' (ID: ' + l.id + ')\n';
      result += '\n';
    }
    result += 'System Labels: ' + system.map(l => l.name).join(', ') + '\n';
    return [{ json: { result } }];
  } catch(e) {
    return [{ json: { error: 'Failed to list labels: ' + e.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Available: search_emails, read_email, send_email, create_draft, list_labels.' } }];
}
